   206→class ListenerManagerImpl : public ListenerManager, Logger::Loggable<Logger::Id::config> {
   207→public:
   208→  ListenerManagerImpl(Instance& server, std::unique_ptr<ListenerComponentFactory>&& factory,
   209→                      WorkerFactory& worker_factory, bool enable_dispatcher_stats,
   210→                      Quic::QuicStatNames& quic_stat_names);
   211→
   212→  void onListenerWarmed(ListenerImpl& listener);
   213→  void inPlaceFilterChainUpdate(ListenerImpl& listener);
   214→
   215→  // Server::ListenerManager
   216→  absl::StatusOr<bool> addOrUpdateListener(const envoy::config::listener::v3::Listener& config,
   217→                                           const std::string& version_info,
   218→                                           bool added_via_api) override;
   219→  void createLdsApi(const envoy::config::core::v3::ConfigSource& lds_config,
   220→                    const xds::core::v3::ResourceLocator* lds_resources_locator) override {
   221→    ASSERT(lds_api_ == nullptr);
   222→    lds_api_ = factory_->createLdsApi(lds_config, lds_resources_locator);
   223→  }
   224→  std::vector<std::reference_wrapper<Network::ListenerConfig>>
   225→  listeners(ListenerState state = ListenerState::ACTIVE) override;
   226→  uint64_t numConnections() const override;
   227→  bool removeListener(const std::string& listener_name) override;
   228→  absl::Status startWorkers(OptRef<GuardDog> guard_dog, std::function<void()> callback) override;
   229→  void stopListeners(StopListenersType stop_listeners_type,
   230→                     const Network::ExtraShutdownListenerOptions& options) override;
   231→  void stopWorkers() override;
   232→  void beginListenerUpdate() override { error_state_tracker_.clear(); }
   233→  void endListenerUpdate(FailureStates&& failure_state) override;
   234→  bool isWorkerStarted() override { return workers_started_; }
   235→  Http::Context& httpContext() { return server_.httpContext(); }
   236→  ApiListenerOptRef apiListener() override;
   237→
   238→  Quic::QuicStatNames& quicStatNames() { return quic_stat_names_; }
   239→
   240→  Instance& server_;
   241→  std::unique_ptr<ListenerComponentFactory> factory_;
   242→
   243→private:
   244→  using ListenerList = std::list<ListenerImplPtr>;
   245→  /**
   246→   * Callback invoked when a listener initialization is completed on worker.
   247→   */
   248→  using ListenerCompletionCallback = std::function<void()>;
   249→
   250→  absl::StatusOr<bool>
   251→  addOrUpdateListenerInternal(const envoy::config::listener::v3::Listener& config,
   252→                              const std::string& version_info, bool added_via_api,
   253→                              const std::string& name);
   254→  bool removeListenerInternal(const std::string& listener_name, bool dynamic_listeners_only);
   255→
   256→  struct DrainingListener {
   257→    DrainingListener(ListenerImplPtr&& listener, uint64_t workers_pending_removal)
   258→        : listener_(std::move(listener)), workers_pending_removal_(workers_pending_removal) {}
   259→
   260→    ListenerImplPtr listener_;
   261→    uint64_t workers_pending_removal_;
   262→  };
   263→
   264→  bool doFinalPreWorkerListenerInit(ListenerImpl& listener);
   265→  void addListenerToWorker(Worker& worker, absl::optional<uint64_t> overridden_listener,
   266→                           ListenerImpl& listener, ListenerCompletionCallback completion_callback);
   267→
   268→  ProtobufTypes::MessagePtr dumpListenerConfigs(const Matchers::StringMatcher& name_matcher);
   269→  static ListenerManagerStats generateStats(Stats::Scope& scope);
   270→  static bool hasListenerWithDuplicatedAddress(const ListenerList& list,
   271→                                               const ListenerImpl& listener);
   272→  void updateWarmingActiveGauges() {
   273→    // Using set() avoids a multiple modifiers problem during the multiple processes phase of hot
   274→    // restart.
   275→    stats_.total_listeners_warming_.set(warming_listeners_.size());
   276→    stats_.total_listeners_active_.set(active_listeners_.size());
   277→  }
   278→  bool listenersStopped(const envoy::config::listener::v3::Listener& config) {
   279→    // Currently all listeners in a given direction are stopped because of the way admin
   280→    // drain_listener functionality is implemented. This needs to be revisited, if that changes - if
   281→    // we support drain by listener name,for example.
   282→    return stop_listeners_type_ == StopListenersType::All ||
   283→           (stop_listeners_type_ == StopListenersType::InboundOnly &&
   284→            config.traffic_direction() == envoy::config::core::v3::INBOUND);
   285→  }
   286→  void incListenerCreateFailureStat() {
   287→    // TODO(mattklein123): Now that we no longer create sockets and apply options on workers,
   288→    // this stat is confusingly named and should be more specific, however it's unclear if it's
   289→    // worth changing.
   290→    stats_.listener_create_failure_.inc();
   291→  }
   292→
   293→  /**
   294→   * Mark a listener for draining. The listener will no longer be considered active but will remain
   295→   * present to allow connection draining.
   296→   * @param listener supplies the listener to drain.
   297→   */
   298→  void drainListener(ListenerImplPtr&& listener);
   299→
   300→  /**
   301→   * Start to draining filter chains that are owned by draining listener but not owned by
   302→   * new_listener. The new listener should have taken over the listener socket and partial of the
   303→   * filter chains from listener. This method is used by in place filter chain update.
   304→   * @param draining_listener supplies the listener to be replaced.
   305→   * @param new_listener supplies the new listener config which is going to replace the draining
   306→   * listener.
   307→   */
   308→  void drainFilterChains(ListenerImplPtr&& draining_listener, ListenerImpl& new_listener);
   309→
   310→  /**
   311→   * Stop a listener. The listener will stop accepting new connections and its socket will be
   312→   * closed.
   313→   * @param listener supplies the listener to stop.
   314→   * @param options additional options to be passed through to shutdownListener.
   315→   * @param completion supplies the completion to be called when all workers are stopped accepting
   316→   * new connections. This completion is called on the main thread.
   317→   */
   318→  void stopListener(Network::ListenerConfig& listener,
   319→                    const Network::ExtraShutdownListenerOptions& options,
   320→                    std::function<void()> completion);
   321→
   322→  /**
   323→   * Get a listener by name. This routine is used because listeners have inherent order in static
   324→   * configuration and especially for tests. Thus, we can't use a map.
   325→   * @param listeners supplies the listener list to look in.
   326→   * @param name supplies the name to search for.
   327→   */
   328→  ListenerList::iterator getListenerByName(ListenerList& listeners, const std::string& name);
   329→
   330→  absl::Status setNewOrDrainingSocketFactory(const std::string& name, ListenerImpl& listener);
   331→  absl::Status createListenSocketFactory(ListenerImpl& listener);
   332→
   333→  void maybeCloseSocketsForListener(ListenerImpl& listener);
   334→  absl::Status setupSocketFactoryForListener(ListenerImpl& new_listener,
   335→                                             const ListenerImpl& existing_listener);
   336→
   337→  ApiListenerPtr api_listener_;
   338→  // Active listeners are listeners that are currently accepting new connections on the workers.
   339→  ListenerList active_listeners_;
   340→  // Warming listeners are listeners that may need further initialization via the listener's init
   341→  // manager. For example, RDS, or in the future KDS. Once a listener is done warming it will
   342→  // be transitioned to active.
   343→  ListenerList warming_listeners_;
   344→  // Draining listeners are listeners that are in the process of being drained and removed. They
   345→  // go through two phases where first the workers stop accepting new connections and existing
   346→  // connections are drained. Then after that time period the listener is removed from all workers
   347→  // and any remaining connections are closed.
   348→  std::list<DrainingListener> draining_listeners_;
   349→  std::list<DrainingFilterChainsManager> draining_filter_chains_manager_;
   350→
   351→  std::vector<WorkerPtr> workers_;
   352→  bool workers_started_{};
   353→  absl::optional<StopListenersType> stop_listeners_type_;
   354→  Stats::ScopeSharedPtr scope_;
   355→  ListenerManagerStats stats_;
   356→  ConfigTracker::EntryOwnerPtr config_tracker_entry_;
   357→  LdsApiPtr lds_api_;
   358→  const bool enable_dispatcher_stats_{};
   359→  using UpdateFailureState = envoy::admin::v3::UpdateFailureState;
   360→  absl::flat_hash_map<std::string, std::unique_ptr<UpdateFailureState>> error_state_tracker_;
   361→  FailureStates overall_error_state_;
   362→  Quic::QuicStatNames& quic_stat_names_;
   363→};
